import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.il0noOp3.js";const p=JSON.parse('{"title":"Roadmap","description":"Planned features, future enhancements, and the long-term vision for AzureScout.","frontmatter":{"description":"Planned features, future enhancements, and the long-term vision for AzureScout."},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md"}'),d={name:"roadmap.md"};function s(n,e,i,c,l,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p><em>See everything. Own your cloud.</em></p><p>This page outlines what&#39;s planned, what&#39;s in progress, and what&#39;s been delivered. Community contributions are welcome — see <a href="./contributing.html">Contributing</a> to get involved.</p><h2 id="current-release-—-v1-0-0" tabindex="-1">Current Release — v1.0.0 <a class="header-anchor" href="#current-release-—-v1-0-0" aria-label="Permalink to &quot;Current Release — v1.0.0&quot;">​</a></h2><p>Released February 2026.</p><table tabindex="0"><thead><tr><th>Area</th><th>What&#39;s included</th></tr></thead><tbody><tr><td>Excel Reports</td><td>170+ worksheets covering all 18 Azure resource categories</td></tr><tr><td>Category Filtering</td><td><code>-Category</code> parameter to scope runs to specific resource types</td></tr><tr><td>AI / ML Coverage</td><td>15 modules: OpenAI, AI Foundry, Azure ML, Cognitive Services, Bot Services, Search</td></tr><tr><td>AVD Coverage</td><td>6 modules: Host Pools, App Groups, Workspaces, Session Hosts, Scaling Plans, Applications</td></tr><tr><td>Arc Coverage</td><td>Sites, SQL Servers, Data Controllers, SQL Managed Instances, Arc-enabled Kubernetes enhancements</td></tr><tr><td>VM &amp; Arc Enrichment</td><td>Backup status, Site Recovery, Update Manager, Advisor score, Monitor metrics, Cost estimates</td></tr><tr><td>Monitor Coverage</td><td>22 modules: Diagnostic settings, alert rules, DCRs, App Insights deep data, autoscale, workbooks</td></tr><tr><td>Markdown / AsciiDoc Export</td><td><code>-OutputFormat Markdown|AsciiDoc</code> generates portable reports alongside Excel/JSON</td></tr><tr><td>Permission Audit</td><td><code>Invoke-AZSCPermissionAudit</code> with ARM + Graph checks, color output, Markdown/AsciiDoc export</td></tr><tr><td>Subscription &amp; MG Completeness</td><td>Captures ALL subscriptions (including empty/disabled) and full MG hierarchy</td></tr><tr><td>Module Naming</td><td>Renamed from <em>AzureTenantInventory</em> to <em>AzureScout</em> (prefix: <code>AZSC</code>)</td></tr></tbody></table><h2 id="near-term-—-v1-1-0" tabindex="-1">Near-term — v1.1.0 <a class="header-anchor" href="#near-term-—-v1-1-0" aria-label="Permalink to &quot;Near-term — v1.1.0&quot;">​</a></h2><p>Focus: quality, reliability, and community onboarding.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>Pester test suite</td><td>Full unit + integration tests for all public functions and key private functions</td><td>:blue_circle: Planned</td></tr><tr><td>PSGallery publish</td><td>Publish <code>AzureScout</code> module to PowerShell Gallery</td><td>:blue_circle: Planned</td></tr><tr><td>GitHub Actions CI</td><td>Run Pester tests on PR + push; block merge on failure</td><td>:blue_circle: Planned</td></tr><tr><td>Category alias documentation</td><td>Comprehensive table of all accepted <code>-Category</code> aliases and their canonical names</td><td>:blue_circle: Planned</td></tr><tr><td>Resource provider pre-flight</td><td>Warn before scan when required providers are not registered in a subscription</td><td>:blue_circle: Planned</td></tr><tr><td>Throttling / retry improvements</td><td>Exponential backoff on ARM 429 responses; configurable <code>-ThrottleDelay</code></td><td>:blue_circle: Planned</td></tr><tr><td><code>Invoke-AzureScout -WhatIf</code></td><td>Show which modules would run without actually executing</td><td>:blue_circle: Planned</td></tr><tr><td>Non-destructive cache</td><td>Prevent <code>ReportCache</code> and <code>DiagramCache</code> from being overwritten on subsequent runs. Each invocation writes to a timestamped (or <code>-RunName</code> named) subfolder. Previous scan data is never lost unless <code>-Force</code> is specified. <code>Clear-AZSCCacheFolder -OlderThan &lt;days&gt;</code> for cleanup.</td><td>:blue_circle: Planned</td></tr></tbody></table><h3 id="visual-dashboard-tabs-darkblue-overview-style-worksheets" tabindex="-1">Visual Dashboard Tabs (DarkBlue &quot;overview-style&quot; worksheets) <a class="header-anchor" href="#visual-dashboard-tabs-darkblue-overview-style-worksheets" aria-label="Permalink to &quot;Visual Dashboard Tabs (DarkBlue &quot;overview-style&quot; worksheets)&quot;">​</a></h3><p>Phase 10 added raw data tabs (Cost Management, Security Overview, Azure Update Manager, Azure Monitor) that collect data into flat tables. The next step is to add <strong>visual dashboard tabs</strong> — styled like the Overview sheet (DarkBlue tab color, EPPlus shapes, pivot charts) — that summarize and visualize the data from those raw tabs.</p><table tabindex="0"><thead><tr><th>Dashboard</th><th>Charts / Visualizations</th><th>Status</th></tr></thead><tbody><tr><td>Cost Dashboard</td><td>Cost by Resource Type (bar), Cost by Subscription (pie), Cost by Region (column), Cost by SKU (bar)</td><td>:blue_circle: Planned</td></tr><tr><td>Security Dashboard</td><td>Assessments by Severity (pie), Findings by Subscription (bar), Defender Plans (column), Active Alerts by Severity (bar)</td><td>:blue_circle: Planned</td></tr><tr><td>Update Manager Dashboard</td><td>Machines by Platform (pie), Machines by OS Type (pie), Machines by Region (column), Machines by Power State (bar), Machines by Subscription (bar)</td><td>:blue_circle: Planned</td></tr><tr><td>Monitor Dashboard</td><td>Alert Rules by Subscription (bar), Action Groups by Subscription (pie), DCRs by Subscription (column), App Insights by Subscription (bar)</td><td>:blue_circle: Planned</td></tr></tbody></table><p>Each dashboard tab will:</p><ul><li>Use DarkBlue tab color (matching Overview, Subscriptions, Advisor)</li><li>Be pinned after the Overview sheet group via <code>MoveAfter</code> in the ordering function</li><li>Contain EPPlus pivot tables + charts generated by <code>Build-AZSCDashboardTabs</code></li><li>Only appear when the corresponding raw data tab has data (no empty dashboards)</li></ul><h2 id="medium-term-—-v1-2-0" tabindex="-1">Medium-term — v1.2.0 <a class="header-anchor" href="#medium-term-—-v1-2-0" aria-label="Permalink to &quot;Medium-term — v1.2.0&quot;">​</a></h2><p>Focus: depth, breadth, and multi-tenant scenarios.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>Multi-tenant scanning</td><td><code>-TenantID</code> accepts multiple tenant IDs. Authenticates to each tenant sequentially, runs the full extraction → processing → reporting pipeline per tenant. Supports combined workbook (with Tenant column) or separate per-tenant workbooks via <code>-MergeOutput</code> switch. Auth failure on one tenant does not block others. Builds on non-destructive cache (v1.1.0) for run isolation.</td><td>:blue_circle: Planned</td></tr><tr><td>Word document export (#22)</td><td><code>-OutputFormat Word</code> generates a <code>.docx</code> report with cover page, table of contents, per-category sections with summary tables, resource counts, and key metrics. Suitable for client deliverables, executive summaries, and formal documentation.</td><td>:blue_circle: Planned</td></tr><tr><td>PDF report export (#23)</td><td><code>-OutputFormat PDF</code> generates a <code>.pdf</code> report with cover page, table of contents, paginated resource tables, and headers/footers. Ideal for archival, compliance evidence, and stakeholder distribution.</td><td>:blue_circle: Planned</td></tr><tr><td>Cost anomaly detection</td><td>Surface Azure Cost Management anomalies in the Cost Management tab</td><td>💡 Idea</td></tr><tr><td>Bicep / IaC gap detection</td><td>Compare discovered resources against known IaC templates; flag unmanaged resources</td><td>💡 Idea</td></tr><tr><td>Resource drift reporting</td><td>Compare two inventory runs and report what was added, removed, or changed</td><td>💡 Idea</td></tr><tr><td>Azure DevOps integration</td><td>Inventory Azure DevOps organizations, projects, pipelines alongside Azure resources</td><td>💡 Idea</td></tr><tr><td>GitHub Actions module</td><td>Publish as a GitHub Action so pipelines can generate inventory reports without local setup</td><td>💡 Idea</td></tr><tr><td>Fabric / Power BI export (#17)</td><td><code>-OutputFormat PowerBI</code> generates a flat normalized CSV bundle (<code>PowerBI/</code> folder) with <code>_metadata.csv</code>, <code>Subscriptions.csv</code>, per-module <code>Resources_*.csv</code> and <code>Entra_*.csv</code> files, and a <code>_relationships.json</code> star-schema manifest for Power BI Desktop / Microsoft Fabric</td><td>✅ Done</td></tr><tr><td>IoT deep coverage</td><td>IoT Hub device registry, Device Provisioning Service, Digital Twins topology</td><td>💡 Idea</td></tr></tbody></table><h2 id="long-term-vision" tabindex="-1">Long-term Vision <a class="header-anchor" href="#long-term-vision" aria-label="Permalink to &quot;Long-term Vision&quot;">​</a></h2><p>AzureScout aims to be the definitive open-source Azure visibility tool for:</p><ul><li><strong>Architects</strong> — understand the full shape of a tenant before designing changes</li><li><strong>Security teams</strong> — identify misconfigured, unmonitored, or over-privileged resources</li><li><strong>FinOps practitioners</strong> — surface cost waste, reservation opportunities, and untagged resources</li><li><strong>Managed service providers</strong> — generate client-ready reports across multiple tenants</li></ul><p>The tool will remain <strong>open-source, PowerShell-native, and Excel-friendly</strong> — no agents, no portals, no licensing fees.</p><h2 id="completed-phases" tabindex="-1">Completed Phases <a class="header-anchor" href="#completed-phases" aria-label="Permalink to &quot;Completed Phases&quot;">​</a></h2><p>All implementation phases from the original migration plan are complete. See the <a href="./changelog.html">Changelog</a> for the full history.</p><table tabindex="0"><thead><tr><th>Phase</th><th>Summary</th></tr></thead><tbody><tr><td>Phase 1-9</td><td>Core engine, module loading, Excel generation, JSON output, Draw.io diagrams, auth methods, connection handling, permission pre-flight</td></tr><tr><td>Phase 10</td><td>Specialized Excel tabs: Cost Management, Security Overview, Azure Update Manager, Azure Monitor</td></tr><tr><td>Phase 11</td><td>All-subscriptions + full MG hierarchy enumeration</td></tr><tr><td>Phase 12</td><td>ARM-only default scope, permission documentation, README overhaul</td></tr><tr><td>Phase 13</td><td>15 new Azure Monitor/Insights modules</td></tr><tr><td>Phase 14</td><td>15 new AI/ML modules</td></tr><tr><td>Phase 15</td><td>6 AVD modules + AVD on Azure Local/Arc detection</td></tr><tr><td>Phase 16</td><td>Arc site configs, Arc SQL Server, Arc Data Services enhancements</td></tr><tr><td>Phase 17</td><td>VM + Arc deep enrichment (metrics, backup, DR, cost, advisor)</td></tr><tr><td>Phase 18</td><td>Category folder alignment + <code>.CATEGORY</code> metadata parsing</td></tr><tr><td>Phase 19</td><td>Richer progress indicators, clear permission error messages</td></tr><tr><td>Phase 20</td><td><code>Invoke-AZSCPermissionAudit</code> + <code>Test-AZSCPermissions</code> refactor</td></tr><tr><td>Phase 21</td><td>Markdown + AsciiDoc export, <code>Export-AZSCMarkdownReport</code>, <code>Export-AZSCAsciiDocReport</code></td></tr></tbody></table><h2 id="suggest-a-feature" tabindex="-1">Suggest a Feature <a class="header-anchor" href="#suggest-a-feature" aria-label="Permalink to &quot;Suggest a Feature&quot;">​</a></h2><p>Open an issue at <a href="https://github.com/thisismydemo/azure-scout/issues" target="_blank" rel="noreferrer">github.com/thisismydemo/azure-scout/issues</a> with the label <code>enhancement</code>.</p><p>Pull requests are welcome — see <a href="./contributing.html">Contributing</a> for guidelines.</p>',27)])])}const m=t(d,[["render",s]]);export{p as __pageData,m as default};
